package dev.hnm.workbench.ui.theme

/**
 * Design tokens **vendored** from `mbaliga/Hyle-Design-System` (`hyle/src/main/java/dev/aarso/hyle/
 * tokens/HyleTokens.kt`, module `dev.aarso:hyle`, generated by its Style Dictionary pipeline from the
 * `tokens` directory's JSON source files).
 *
 * This is a deliberate **copy, not a build dependency**. Hyle has no published Maven/JitPack artifact —
 * its only documented consumption path is a git submodule + Gradle `includeBuild` aimed at the author's
 * other Android-only sibling repos — and its actual visual composables (glass "Pane", the dot-grid
 * "room" substrate, motion/glow rendering) are implemented as AGSL `RuntimeShader` code requiring
 * Android API 33+, living only in `:hyle-probe` (a throwaway demo app, not the reusable `:hyle` library).
 * None of that is usable from a Compose **Multiplatform** module that must run on both JVM desktop and
 * Android `minSdk 31`.
 *
 * What IS portable — and vendored verbatim here — is Hyle's data layer: these color/dimension/duration
 * tokens, plus the [Finish]/[Pulse]/[RadiantHues]/[Provenance] contract in `HyleProvenance.kt`, both of
 * which are plain Kotlin in the source repo with zero Android/Compose imports. Everything *visual* built
 * from these tokens in this module ([HyleTheme], `DotGridSubstrate`, `GlassSurface`, `ProvenanceGlow`) is
 * an original Compose Multiplatform implementation informed by Hyle's tokens and philosophy — not a
 * literal port of Hyle's AGSL shaders. Re-sync by hand if the upstream tokens change; there is no
 * automatic sync mechanism.
 */
object HyleTokens {

    /** ARGB colors as 0xAARRGGBB Long, matching the source token format exactly. */
    object Color {
        const val FieldVoid: Long = 0xFF000000L
        const val FieldNear: Long = 0xFF0A0809L
        const val FieldRaised: Long = 0xFF121212L
        const val FieldDeep: Long = 0xFF050009L

        const val InkPure: Long = 0xFFECE8E4L
        const val InkFull: Long = 0xEBECE8E4L
        const val InkDim: Long = 0x6BECE8E4L
        const val InkFaint: Long = 0x2EECE8E4L

        const val AccentViolet: Long = 0xFF8E7BFFL
        const val AccentVioletBright: Long = 0xFFA593FFL
        const val AccentVioletDeep: Long = 0xFF7867E6L

        const val ProvenanceNative: Long = 0xFFC7EF9EL
        const val ProvenanceCloud: Long = 0xFF35E0FFL

        const val HairlineDefault: Long = 0x14FFFFFFL
        const val HairlineStrong: Long = 0x24FFFFFFL

        const val GlassPane: Long = 0x850A0809L

        const val SignalDanger: Long = 0xFFE5564BL
        const val SignalWarning: Long = 0xFFE0941AL
        const val SignalSuccess: Long = 0xFF5BBF7AL

        const val MaterialStone: Long = 0xFF9B958CL
        const val MaterialSmog: Long = 0xFFCC1A0AL
        const val MaterialLight: Long = 0xFFFFD2B0L

        const val TextPrimary: Long = 0xEBECE8E4L
        const val TextSecondary: Long = 0x6BECE8E4L
        const val TextFaint: Long = 0x2EECE8E4L
        const val TextInverse: Long = 0xFF0A0809L
        const val TextAccent: Long = 0xFF8E7BFFL

        const val BackgroundField: Long = 0xFF000000L
        const val BackgroundSurface: Long = 0xFF121212L
        const val BackgroundGlass: Long = 0x850A0809L
        const val BackgroundInverse: Long = 0xFFECE8E4L

        const val BorderHairline: Long = 0x14FFFFFFL
        const val BorderStrong: Long = 0x24FFFFFFL
        const val BorderFocus: Long = 0xFF8E7BFFL

        const val ActionPrimary: Long = 0xFF8E7BFFL
        const val ActionPrimaryHover: Long = 0xFFA593FFL
        const val ActionPrimaryActive: Long = 0xFF7867E6L
        const val ActionOnPrimary: Long = 0xFF0A0809L

        const val FeedbackDanger: Long = 0xFFE5564BL
        const val FeedbackWarning: Long = 0xFFE0941AL
        const val FeedbackSuccess: Long = 0xFF5BBF7AL

        // "Control" tokens — a hardware-control-surface subset that happens to be pixel-identical to
        // the recorder2 palette already used across this app (ControlScreen/Ink/Dim == Screen/Ink/InkDim).
        const val ControlSurface: Long = 0xFF16161AL
        const val ControlSurfaceRaised: Long = 0xFF212128L
        const val ControlSurfaceHigh: Long = 0xFF2C2C34L
        const val ControlGroove: Long = 0xFF050506L
        const val ControlEdge: Long = 0xFF3A3A44L
        const val ControlRim: Long = 0x29FFFFFFL
        const val ControlRimSoft: Long = 0x17FFFFFFL
        const val ControlIndicator: Long = 0xFF6B6760L
        const val ControlScreen: Long = 0xFF141210L
        const val ControlScreenInk: Long = 0xFFDDDBD6L
        const val ControlScreenDim: Long = 0xFF5C5A56L
    }

    /** Spacing/radius/size scale, dp (type scale is sp — same numeric values). */
    object Dimension {
        const val Spacing0 = 0
        const val Spacing1 = 4
        const val Spacing2 = 8
        const val Spacing3 = 12
        const val Spacing4 = 16
        const val Spacing5 = 20
        const val Spacing6 = 24
        const val Spacing8 = 32
        const val Spacing10 = 40
        const val Spacing12 = 48
        const val Spacing16 = 64

        const val RadiusNone = 0
        const val RadiusSm = 4
        const val RadiusMd = 8
        const val RadiusLg = 12
        const val RadiusXl = 16
        const val RadiusFull = 9999

        const val SizeControlSm = 32
        const val SizeControlMd = 40
        const val SizeControlLg = 48

        const val SizeBorderThin = 1
        const val SizeBorderThick = 2

        const val FontSizeMicro = 10
        const val FontSizeLabel = 11
        const val FontSizeXs = 12
        const val FontSizeSm = 14
        const val FontSizeMd = 16
        const val FontSizeLg = 18
        const val FontSizeXl = 20
        const val FontSize2xl = 24
        const val FontSize3xl = 32
    }

    /** Motion durations, ms — the portable half of Hyle's "motion primitives" (no shader/spring physics). */
    object Duration {
        const val Instant = 120
        const val Calm = 300
        const val Pane = 420
    }
}
